const myEmail = "mmccall@bigpanda.io";
const internalDomain = "@bigpanda.io";

const calls = $input.all();
const allCalls = calls[0].json;

// Merge any additional returned call batches into one call list.
for (let c = 1; c < calls.length; c++) {
  allCalls.calls = [...allCalls.calls, ...calls[c].json.calls];
}

// Loop backward so removing calls with splice does not skip any items.
for (let i = allCalls.calls.length - 1; i >= 0; i--) {
  const call = allCalls.calls[i];

  // Default to an empty participant list if the call has no parties field.
  const parties = call.parties || [];

  // Normalize participant emails and remove parties that do not have an email address.
  const partyEmails = parties
    .map(party => party.emailAddress?.toLowerCase())
    .filter(Boolean);

  // Default to an empty title if metadata or title is missing.
  const title = call.metaData?.title || "";

  // Identify which calls have my email as one of the participants.
  const hasMyEmail = partyEmails.includes(myEmail.toLowerCase());

  // Identify internal-only calls where every participant has a BigPanda email.
  // These are filtered out because there are no external/customer attendees.
  const isInternalOnlyCall =
    partyEmails.length > 0 &&
    partyEmails.every(email => email.endsWith(internalDomain));

  if( hasMyEmail) {
  console.log(title + ' ' + isInternalOnlyCall);
  }

  // Filter out calls where the RSA is handling task management.
  const hasRSA = title.includes("Labcorp Working Session");

  // Remove the call if:
  // - I was not a participant
  // - It was internal-only
  // - It matched the RSA / working session exclusion
  if (!hasMyEmail || isInternalOnlyCall || hasRSA) {
    allCalls.calls.splice(i, 1);
  }
}

return allCalls;

const inputArray = $input.item.json;  // your original array
const outputArray = [];


// slim down metadata
const slimMeta = {
  id:    inputArray.metaData && inputArray.metaData.id,
  title: inputArray.metaData && inputArray.metaData.title
};

  // slim down parties
  const slimParties = [];
  const parties = Array.isArray(inputArray.parties) ? inputArray.parties : [];
  for (let k = 0; k < parties.length; k++) {
    const p = parties[k];
    slimParties.push({
      speaker_id:    p.speakerId,
      speaker_email: p.emailAddress,
      speaker_name:  p.name
    });
  }

  // assemble slimmed call
  outputArray.push({
    metaData: slimMeta,
    parties:  slimParties
  });


let slimCalls = { "calls": outputArray};
return slimCalls;

