// =============================================================================
// Gong → ClickUp : one Code node that does everything
// Place this BETWEEN the LLM node and the ClickUp HTTP Request node.
//
// It accepts the LLM output (an array of task objects, an object with `.tasks`,
// or a JSON string — even one wrapped in ```json fences), then for each task:
//   1. validates it against the BigPanda task standard
//   2. ASSEMBLES the flat fields into a single markdown `description`
//      (real newlines live here, safely in code — never in the model's JSON)
//   3. builds a ready-to-send ClickUp `payload` object
//
// Then in the ClickUp HTTP Request node set:
//   Body Content Type = JSON
//   Specify Body = Using JSON
//   JSON =  {{ $json.payload }}
// Passing an OBJECT (not hand-typed JSON text) lets n8n escape everything, so
// "bad control character" / "not valid JSON" errors cannot happen.
//
// Wire an IF node on `_valid`: true -> ClickUp; false -> review branch.
// =============================================================================

// ---- config -----------------------------------------------------------------
const TASK_CATEGORY_FIELD_ID = "d528c55b-b687-4a89-aec2-ffad5fb920bb";
const PRIORITY_MAP = { urgent: 1, high: 2, normal: 3, low: 4 }; // ClickUp priority codes
const VOCAB = new Set([
  "gong-generated", "customer-commitment", "waiting-on-customer", "internal-blocker",
  "product-feedback", "renewal", "expansion", "needs-scheduling", "needs-detail",
]);
// Optional: resolve assignee names -> ClickUp user IDs. Add teammates as needed.
// Leave a name out and the task simply won't get an assignee set (it'll rely on
// task-prioritizer to assign later).
const ASSIGNEE_IDS = {
  "Michael McCall": 57194708,
};

const STATUSES = new Set(["New", "In Progress", "On Hold", "Complete"]);
const isDate = v => typeof v === "string" && /^\d{4}-\d{2}-\d{2}$/.test(v);
const isWeekend = v => { const d = new Date(v + "T00:00:00Z").getUTCDay(); return d === 0 || d === 6; };

// ---- accept whatever shape the LLM node hands us ----------------------------
function coerceTasks(input) {
  let data = input;
  if (typeof data === "string") {
    data = JSON.parse(data.replace(/^```(?:json)?\s*|\s*```$/g, "").trim());
  }
  if (Array.isArray(data)) return data;
  if (data && Array.isArray(data.tasks)) return data.tasks;
  return [data];
}

// ---- assemble the single markdown description -------------------------------
function buildDescription(t) {
  const lines = [];
  lines.push("## The ask", t.the_ask || "");
  lines.push("## Definition of done", t.definition_of_done || "");
  lines.push("## Stakeholders");
  const sh = Array.isArray(t.stakeholders) ? t.stakeholders : [];
  if (sh.length) sh.forEach(s => lines.push(`- ${s}`)); else lines.push("- None identified");
  lines.push("## Forcing function", t.forcing_function || "None stated");
  lines.push("## Context", t.context || "");
  let source = `- Gong: ${t.call_title || "(untitled call)"}`;
  if (t.source_call_url) source += ` (${t.source_call_url})`;
  if (t.source_call_date) source += ` — ${t.source_call_date}`;
  if (t.timestamp) source += ` @ ${t.timestamp}`;
  lines.push("## Source", source);
  lines.push("## Assignee: ", t.assignee);
  return lines.join("\n");
}

// ---- validate against the standard ------------------------------------------
function validate(t) {
  const e = [];
  if (!STATUSES.has(t.task_status)) e.push(`bad task_status: ${t.task_status}`);
  if (!t.task_list_id) e.push("missing task_list_id");
  const idx = Number(t.task_category_index);
  if (!Number.isInteger(idx) || idx < 0 || idx > 5) e.push("task_category_index must be 0-5");

  if (!t.the_ask) e.push("missing the_ask");
  if (!t.definition_of_done) e.push("missing definition_of_done");
  if (t.stakeholders !== undefined && !Array.isArray(t.stakeholders)) e.push("stakeholders must be an array");

  const tags = Array.isArray(t.tags) ? t.tags : [];
  if (!tags.includes("gong-generated")) e.push("tags must include gong-generated");
  for (const tag of tags) if (!VOCAB.has(tag)) e.push(`tag not in vocabulary: ${tag}`);

  const noOwner = t.assignee === null || t.assignee === "" || t.assignee === undefined;
  if (noOwner && !tags.includes("needs-detail")) e.push("null assignee requires needs-detail tag");

  if (t.due_date !== null && t.due_date !== undefined) {
    if (!isDate(t.due_date)) e.push("due_date must be YYYY-MM-DD or null");
    else if (isWeekend(t.due_date)) e.push("due_date falls on a weekend");
  }
  if (t.priority !== null && t.priority !== undefined) {
    if (!PRIORITY_MAP[t.priority]) e.push(`bad priority: ${t.priority}`);
    if (!t.due_date) e.push("priority set without a due_date");
  }
  if (t.level_of_effort != null && !["Small", "Medium", "Large"].includes(t.level_of_effort))
    e.push(`bad level_of_effort: ${t.level_of_effort}`);

  if (t.task_status === "In Progress" && !t.clickup_id) e.push("In Progress task missing clickup_id");
  return e;
}

// ---- build the ClickUp request payload --------------------------------------
function buildPayload(t, description) {
  const tags = Array.isArray(t.tags) ? t.tags : [];
  const payload = {
    name: t.task_title,
    markdown_content: description,   // swap to `description` if you prefer plain text
    tags,
    custom_fields: [{ id: TASK_CATEGORY_FIELD_ID, value: Number(t.task_category_index) }],
  };
  const id = t.assignee && ASSIGNEE_IDS[t.assignee];
  if (id) payload.assignees = [id];                              // numeric user IDs only
  if (t.due_date) payload.due_date = Date.parse(t.due_date + "T17:00:00Z"); // epoch ms
  if (t.due_date && t.priority && PRIORITY_MAP[t.priority]) payload.priority = PRIORITY_MAP[t.priority];
  return payload;
}

// ---- main -------------------------------------------------------------------
const out = [];
for (const item of $input.all()) {
  // The LLM output can sit in different places depending on the node; try the common ones.
  const src = item.json.output ?? item.json.text ?? item.json.message?.content ?? item.json;
  let tasks;
  try {
    tasks = coerceTasks(src);
  } catch (err) {
    out.push({ json: { _valid: false, _errors: ["could not parse LLM output: " + err.message], _raw: src } });
    continue;
  }
  for (const t of tasks) {
    const errors = validate(t);
    const description = buildDescription(t);
    const payload = buildPayload(t, description);
    out.push({ json: { ...t, description, payload, _valid: errors.length === 0, _errors: errors } });
  }
}
return out;

// Parse and subtract 30 minutes
const minus30 = DateTime.fromISO($input.first().json.timestamp).minus({ minutes: 30 }).toISO();

// Parse and subtract 300 minutes for testing
const minus7200 = DateTime.fromISO($input.first().json.timestamp).minus({ minutes: 7200 }).toISO();

// Attach back onto the JSON
$input.first().json.timestampMinus30 = minus30;
$input.first().json.timestampMinus7200 = minus7200;
return $input.first();

